module top_module(
 input [31:0] x, y,
 output [31:0] zlow, zhigh);integer i; 
 reg [31:0] negated_bits;

 always @* begin
	for(i=0; i<32; i= i+1) begin

		if(x[i] == 1)
			negated_bits[i] = 0;
		else
			negated_bits[i] = 1;

	end
 end

 assign zlow = negated_bits;
 assign zhigh = 0;

endmodule
